import{_ as t,c as o,o as a,ag as s}from"./chunks/framework.DEnUjgmn.js";const p=JSON.parse('{"title":"How to contribute 🤝","description":"","frontmatter":{},"headers":[],"relativePath":"Contribute/index.md","filePath":"Contribute/index.md"}'),i={name:"Contribute/index.md"};function n(r,e,l,c,u,d){return a(),o("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /camomilla-core/Contribute.md for this page in Markdown format</div><h1 id="how-to-contribute-🤝" tabindex="-1">How to contribute 🤝 <a class="header-anchor" href="#how-to-contribute-🤝" aria-label="Permalink to &quot;How to contribute 🤝&quot;">​</a></h1><p>Any contribution is welcome! Whether you want to report a bug, suggest an enhancement, or write code, we are happy to help you. Please read the following guidelines before contributing.</p><h3 id="✉️-reporting-bugs" tabindex="-1">✉️ Reporting bugs <a class="header-anchor" href="#✉️-reporting-bugs" aria-label="Permalink to &quot;✉️ Reporting bugs&quot;">​</a></h3><p>You can report bugs by creating an issue on the <a href="https://github.com/camomillacms/camomilla-core/issues" target="_blank" rel="noreferrer">issue tracker</a>.</p><p>Please include as much information as possible, including:</p><ul><li>The version of Camomilla you are using</li><li>The version of Django you are using</li><li>The version of Python you are using</li><li>The operating system you are using</li><li>The steps to reproduce the bug</li><li>The expected result</li><li>The actual result</li><li>Any other information that might be useful</li></ul><h3 id="☝️-suggesting-enhancements" tabindex="-1">☝️ Suggesting enhancements <a class="header-anchor" href="#☝️-suggesting-enhancements" aria-label="Permalink to &quot;☝️ Suggesting enhancements&quot;">​</a></h3><p>You can suggest enhancements by creating an issue on the <a href="https://github.com/camomillacms/camomilla-core/issues" target="_blank" rel="noreferrer">issue tracker</a>.</p><p>Enhancements can be anything from a new feature to a small improvement in the documentation. Even if you are not sure about your idea, feel free to open an issue and discuss it with us. Every idea is welcome!</p><h3 id="🧑‍💻-your-first-code-contribution" tabindex="-1">🧑‍💻 Your first code contribution <a class="header-anchor" href="#🧑‍💻-your-first-code-contribution" aria-label="Permalink to &quot;🧑‍💻 Your first code contribution&quot;">​</a></h3><p>If you want to contribute to Camomilla by writing code, you can start by looking at the <a href="https://github.com/camomillacms/camomilla-core/issues" target="_blank" rel="noreferrer">issue tracker</a>. There you can find issues that are marked as &quot;good first issue&quot; and are suitable for new contributors. If you want to work on an issue, please leave a comment on it so that we can assign it to you. If you want to work on something else, please open an issue first so that we can discuss it. This way we can avoid duplicated work and make sure that your contribution will be accepted. Once you have finished your work, you can open a pull request. We will review it and, if everything is fine, we will merge it. If you are not sure about something, feel free to open a pull request as soon as possible so that we can discuss it. We are always happy to help!</p><h3 id="💅-coding-conventions" tabindex="-1">💅 Coding conventions <a class="header-anchor" href="#💅-coding-conventions" aria-label="Permalink to &quot;💅 Coding conventions&quot;">​</a></h3><p>We try to follow the <a href="https://docs.djangoproject.com/en/dev/internals/contributing/writing-code/coding-style/" target="_blank" rel="noreferrer">Django coding style</a>. Please make sure to follow it when writing code for Camomilla. If you are not sure about something, feel free to ask us. We also use <code>black</code> to format our code, so please make sure to run it before opening a pull request. You can run it by executing the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> format</span></span></code></pre></div><h3 id="可-commit-conventions" tabindex="-1">🉑 Commit Conventions <a class="header-anchor" href="#可-commit-conventions" aria-label="Permalink to &quot;🉑 Commit Conventions&quot;">​</a></h3><p>We use <a href="https://www.conventionalcommits.org/en/v1.0.0/" target="_blank" rel="noreferrer">semantic commit messages</a> to make it easier to understand the changes made in each commit. Please use the following format for your commit messages:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</span></span>
<span class="line"><span>&lt;body&gt;</span></span>
<span class="line"><span>&lt;footer&gt;</span></span></code></pre></div><p>Where:</p><ul><li><code>&lt;type&gt;</code> is one of the following: <code>feat</code>, <code>fix</code>, <code>docs</code>, <code>style</code>, <code>refactor</code>, <code>perf</code>, <code>test</code>, <code>chore</code></li><li><code>&lt;scope&gt;</code> is optional and can be used to specify the scope of the change (e.g. <code>camomilla</code>, <code>theme</code>, <code>admin</code>, etc.)</li><li><code>&lt;subject&gt;</code> is a short description of the change (max 72 characters)</li><li><code>&lt;body&gt;</code> is an optional longer description of the change</li><li><code>&lt;footer&gt;</code> is an optional footer that can be used to reference issues or pull requests (e.g. <code>Closes #123</code>, <code>Fixes #456</code>)</li></ul><h3 id="🧪-running-tests" tabindex="-1">🧪 Running tests <a class="header-anchor" href="#🧪-running-tests" aria-label="Permalink to &quot;🧪 Running tests&quot;">​</a></h3><p>We always test pull requests before merging them. To avoid issues, please make sure that your code passes the tests before opening a pull request. You can run the tests by executing the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>We test against a variety of Django and Python versions, so please make sure that your code passes the tests for all of them. You can check the list of tested version in our <a href=".github/workflows/ci.yml">CI configuration</a>.</p>`,24)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
